UPDATE email_templates SET body_html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f4f4f4;font-family:Arial,Helvetica,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f4f4;padding:20px 0;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:linear-gradient(135deg,#D4A017,#C4922A);padding:30px;text-align:center;"><h1 style="color:#ffffff;margin:0;font-size:22px;font-weight:bold;">🎉 Dziękujemy za udział!</h1><p style="color:#fff8e1;margin:8px 0 0;font-size:14px;">{{event_title}} — {{event_date}}</p></td></tr><tr><td style="padding:30px 35px;"><p style="color:#333;font-size:15px;line-height:1.7;margin:0 0 15px;">Cześć <strong>{{imię}}</strong>,</p><p style="color:#333;font-size:15px;line-height:1.7;margin:0 0 15px;">bardzo dziękujemy za uczestnictwo w naszym ostatnim webinarze pt. „<strong>{{event_title}}</strong>". Cieszymy się, że tak ważny temat zgromadził osoby, które chcą świadomie zadbać o swoje zdrowie i komfort życia.</p><p style="color:#333;font-size:15px;line-height:1.7;margin:0 0 15px;">W ramach podziękowania za wspólnie spędzony czas przygotowaliśmy dla Ciebie obiecywany materiał. Poniżej znajdziesz link do pobrania pliku:</p><div style="background:#f0fdf4;padding:15px 20px;border-radius:8px;margin:20px 0;border-left:4px solid #16a34a;"><p style="color:#333;font-size:15px;line-height:1.6;margin:0;">📄 <strong>PDF: Twój Osobisty Protokół Zdrowia: Endometrioza i Stan Zapalny</strong></p><p style="color:#666;font-size:13px;margin:5px 0 0;">(plik w załączniku lub link od admina poniżej)</p></div>{{custom_message}}<p style="color:#333;font-size:15px;line-height:1.7;margin:20px 0 15px;">Mamy nadzieję, że zawarte w nim wskazówki będą cennym wsparciem w Twojej codziennej drodze do lepszego samopoczucia.</p><h3 style="color:#D4A017;font-size:17px;margin:25px 0 12px;border-bottom:2px solid #D4A017;padding-bottom:8px;">Jak możesz działać dalej?</h3><p style="color:#333;font-size:15px;line-height:1.7;margin:0 0 15px;">Jeśli chcesz wdrożyć zdobytą wiedzę w życie i zależy Ci na sprawdzonych rozwiązaniach, zapraszamy do kontaktu z osobą, która zaprosiła Cię na nasze wydarzenie. U niej dowiesz się, jak:</p><ul style="color:#333;font-size:15px;line-height:1.8;margin:0 0 15px;padding-left:20px;"><li><strong>Nabyć najwyższej jakości kwasy Omega-3</strong>, kluczowe w walce ze stanem zapalnym.</li><li><strong>Uzyskać dostęp do naszej platformy edukacyjnej</strong>, która zawiera bogatą bazę specjalistycznej wiedzy.</li><li><strong>Brać udział w zamkniętych spotkaniach zdrowotnych</strong>, prowadzonych przez wybitnych ekspertów.</li></ul><p style="color:#333;font-size:15px;line-height:1.7;margin:0 0 15px;">U tej samej osoby możesz również poprosić o <strong>bezpłatny dostęp do nagrania</strong> z wykładu dr inż. Karoliny Kowalczyk („Endometrioza. Jak odzyskać kontrolę i poprawić jakość życia"), aby w dowolnej chwili wrócić do najważniejszych informacji.</p><div style="background:#FFF8E1;padding:15px 20px;border-radius:8px;margin:20px 0;border-left:4px solid #D4A017;"><p style="color:#333;font-size:15px;line-height:1.6;margin:0;">👉 <strong>Skontaktuj się ze swoim opiekunem (osobą zapraszającą) już dziś</strong>, aby uzyskać dostęp do tych wszystkich materiałów i narzędzi.</p></div><p style="color:#333;font-size:15px;line-height:1.7;margin:20px 0 5px;">Życzymy ogromu zdrowia!</p><p style="color:#D4A017;font-size:16px;font-weight:bold;margin:0;">Zmieniamy życie ludzi na lepsze. 💛</p></td></tr><tr><td style="background-color:#1a1a2e;padding:20px;text-align:center;"><p style="color:#999;font-size:12px;margin:0;">© 2025 Pure Life · Wszystkie prawa zastrzeżone</p></td></tr></table></td></tr></table></body></html>', subject = '🎉 Dziękujemy za udział w webinarze! {{event_title}}' WHERE internal_name = 'webinar_followup';